<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;use App\Services\AssetActivityService;
final class EquipmentCustodyController{
 public function index():void{Auth::requireRole('owner','administrator','office','crew_leader');$pdo=Database::connection();$rows=$pdo->query('SELECT c.*,i.name item_name,v.name vehicle_name,u.name assigned_name,ib.name issued_by_name FROM equipment_custody c LEFT JOIN inventory_items i ON i.id=c.inventory_item_id LEFT JOIN vehicles v ON v.id=c.vehicle_id JOIN users u ON u.id=c.assigned_user_id LEFT JOIN users ib ON ib.id=c.issued_by ORDER BY c.returned_at IS NULL DESC,c.issued_at DESC')->fetchAll();View::render('portal/equipment-custody/index',['title'=>'Equipment Custody','rows'=>$rows,'items'=>$pdo->query('SELECT id,name FROM inventory_items ORDER BY name')->fetchAll(),'vehicles'=>$pdo->query('SELECT id,name FROM vehicles ORDER BY name')->fetchAll(),'users'=>$pdo->query("SELECT id,name FROM users WHERE status='active' ORDER BY name")->fetchAll()],'portal');}
 public function issue():void{Auth::requireRole('owner','administrator','office','crew_leader');verify_csrf();Database::connection()->prepare('INSERT INTO equipment_custody(inventory_item_id,vehicle_id,assigned_user_id,quantity,expected_return_at,condition_out,notes,issued_by) VALUES(?,?,?,?,?,?,?,?)')->execute([($_POST['inventory_item_id']??'')!==''?(int)$_POST['inventory_item_id']:null,($_POST['vehicle_id']??'')!==''?(int)$_POST['vehicle_id']:null,(int)$_POST['assigned_user_id'],(float)($_POST['quantity']??1),($_POST['expected_return_at']??'')?:null,trim($_POST['condition_out']??''),trim($_POST['notes']??''),Auth::id()]);$id=(int)Database::connection()->lastInsertId();AuditService::log('equipment.issued','equipment_custody',$id);if(($_POST['vehicle_id']??'')!=='')AssetActivityService::record('vehicle',(int)$_POST['vehicle_id'],'custody_assigned','Equipment custody assigned',['custody_id'=>$id,'assigned_user_id'=>(int)$_POST['assigned_user_id']],Auth::id());if(($_POST['inventory_item_id']??'')!=='')AssetActivityService::record('inventory',(int)$_POST['inventory_item_id'],'custody_issued','Equipment issued',['custody_id'=>$id,'assigned_user_id'=>(int)$_POST['assigned_user_id'],'quantity'=>(float)($_POST['quantity']??1)],Auth::id());redirect('/portal/equipment-custody');}
 public function returnItem(int $id):void{Auth::requireRole('owner','administrator','office','crew_leader');verify_csrf();Database::connection()->prepare('UPDATE equipment_custody SET returned_at=NOW(),condition_in=?,returned_to=? WHERE id=? AND returned_at IS NULL')->execute([trim($_POST['condition_in']??''),Auth::id(),$id]);$pdo=Database::connection();$q=$pdo->prepare('SELECT * FROM equipment_custody WHERE id=?');$q->execute([$id]);$row=$q->fetch();AuditService::log('equipment.returned','equipment_custody',$id);if($row){if(!empty($row['vehicle_id']))AssetActivityService::record('vehicle',(int)$row['vehicle_id'],'custody_returned','Equipment custody returned',['custody_id'=>$id],Auth::id());if(!empty($row['inventory_item_id']))AssetActivityService::record('inventory',(int)$row['inventory_item_id'],'custody_returned','Equipment returned',['custody_id'=>$id,'condition_in'=>trim($_POST['condition_in']??'')],Auth::id());}redirect('/portal/equipment-custody');}
}
